" Minimum valid CDS view structure
@AbapCatalog.sqlViewName: 'ZMIN_V'     " max 16 chars
@AccessControl.authorizationCheck: #NOT_REQUIRED
@EndUserText.label: 'Minimum CDS View'
define view ZCDS_MINIMUM_EXAMPLE
  as select from mara
{
  key mara.matnr as Material,
      mara.mtart  as MaterialType
}

" ABAP usage
SELECT Material, MaterialType
  FROM zcds_minimum_example
  WHERE MaterialType = 'FERT'
  INTO TABLE @DATA(lt_mat).

" Annotations - practical mandatory set
@AbapCatalog.sqlViewName: 'ZANNO_DEMO_V'  " SE11 name - needed
@AbapCatalog.compiler.compareFilter: true  " performance
@AccessControl.authorizationCheck: #CHECK  " security
@EndUserText.label: 'Demo View with Annotations' " description
define view ZCDS_ANNOTATION_DEMO
  as select from lfa1
{
  key lfa1.lifnr as Vendor,
      lfa1.name1  as VendorName,
      lfa1.land1  as Country
}

" OData: add this annotation
" @OData.publish: true
" Analytics: add this
" @Analytics.dataCategory: #CUBE

" Layer 1: Interface View (tables)
@AbapCatalog.sqlViewName: 'ZI_PO_HDR_V'
define view ZI_PO_HEADER
  as select from ekko
  association [0..*] to ekpo as _Items
    on $projection.PO = _Items.ebeln
{ key ekko.ebeln as PO, ekko.lifnr as Vendor,
      ekko.bedat as DocDate, _Items }

" Layer 2: Consumption View (Fiori UI)
@OData.publish: true
define view ZC_PO_LIST
  as select from ZI_PO_HEADER  " uses interface view
{
  @UI.lineItem: [{ position: 10 }]
  key PO,
  @UI.lineItem: [{ position: 20 }]
      Vendor,
  @UI.selectionField: [{ position: 10 }]
      DocDate
}

@AbapCatalog.sqlViewName: 'ZORDSTATUS_V'
@AccessControl.authorizationCheck: #CHECK
@EndUserText.label: 'Order Status with Labels'
define view ZCDS_ORDER_STATUS
  as select from vbak
{
  key vbak.vbeln as OrderNumber,
      vbak.auart  as OrderType,
      vbak.netwr  as NetValue,
      case vbak.cmgst
        when 'A' then 'Not Relevant'
        when 'B' then 'Not Blocked'
        when 'C' then 'Partially Blocked'
        when 'D' then 'Fully Blocked'
        else          'Unknown'
      end           as CreditStatusTxt,
      vbak.erdat  as CreatedOn
}
where vbak.auart = 'OR'

" SAP Standard VDM - I_ prefix (do not modify)
" I_SalesOrder, I_Material, I_CompanyCode exist in system

" Custom Consumption View - built on SAP standard
@OData.publish: true
define view ZC_MY_SALES_ORDER
  as select from I_SalesOrder  " SAP standard interface view
{
  @UI.lineItem: [{ position: 10 }]
  key SalesOrder,
  @UI.lineItem: [{ position: 20 }]
      SoldToParty,
  @UI.lineItem: [{ position: 30 }]
      NetAmountInDisplayCurrency,
  @UI.selectionField: [{ position: 10 }]
      CreationDate
}
where SalesOrderType = 'OR'

" Layer 1: Interface View - data model
@AbapCatalog.sqlViewName: 'ZI_CUST_V'
define view ZI_CUSTOMER
  as select from kna1
  association [0..1] to knb1 as _CompanyData
    on $projection.Customer = _CompanyData.kunnr
{ key kna1.kunnr as Customer,
      kna1.name1  as Name, kna1.land1 as Country,
      _CompanyData }

" Layer 3: Consumption View - Fiori UI
@OData.publish: true
define view ZC_CUSTOMER_LIST
  as select from ZI_CUSTOMER
{
  @UI.lineItem: [{ position: 10 }]
  key Customer,
  @UI.lineItem: [{ position: 20 }]
      Name,
  @UI.selectionField: [{ position: 10 }]
      Country
}

@Analytics.dataCategory: #CUBE
@Analytics.query: true
@AccessControl.authorizationCheck: #CHECK
@EndUserText.label: 'FI Revenue Cube - Embedded Analytics'
define view ZCDS_FI_REVENUE_CUBE
  as select from acdoca
{
  key acdoca.rldnr,
  key acdoca.rbukrs  as CompanyCode,
  key acdoca.gjahr   as FiscalYear,
  key acdoca.prctr   as ProfitCenter,
  key acdoca.racct   as GLAccount,
      @Aggregation.default: #SUM
      @Semantics.amount.currencyCode: 'Currency'
      sum(acdoca.hsl) as Amount,
      acdoca.rhcur    as Currency
} group by acdoca.rldnr, acdoca.rbukrs, acdoca.gjahr,
           acdoca.prctr, acdoca.racct, acdoca.rhcur

" RAP: CDS Entity View (not classic define view)
define view entity ZI_LEAVE_REQUEST
  as select from zhr_leave_req
{
  key leave_id    as LeaveID,
      employee_id as EmployeeID,
      start_date  as StartDate,
      end_date    as EndDate,
      leave_type  as LeaveType,
      status      as Status
}

" Behavior Definition (in separate .bdef file)
managed implementation in class
  zbp_i_leave_request unique;
strict ( 2 );
define behavior for ZI_LEAVE_REQUEST alias Leave
persistent table zhr_leave_req
{
  create; update; delete;
  action ApproveLeave;
  validation checkDateOverlap on save { field StartDate, EndDate; }
}

" Step 1: CDS view with authorization annotation
@AbapCatalog.sqlViewName: 'ZVKORG_V'
@AccessControl.authorizationCheck: #CHECK  " mandatory
define view ZCDS_SALES_ORG_VIEW
  as select from vbak
{ key vbak.vbeln as Order, vbak.vkorg as SalesOrg,
      vbak.netwr as Amount }

" Step 2: DCL source - same name as CDS view
" (New ABAP Development Tools object type: DCL Source)
@MappingRole: true
define role ZCDS_SALES_ORG_VIEW
{
  grant select on ZCDS_SALES_ORG_VIEW
    where (SalesOrg) = aspect pfcg_auth(
      V_VBAK_VKO,   " authorization object
      VKORG,        " authorization field
      ACTVT = '03'  " display activity
    );
}

@OData.publish: true
@UI.headerInfo: { typeName: 'Leave Request',
                  typeNamePlural: 'Leave Requests',
                  title: { type: #STANDARD, value: 'LeaveID' } }
define view ZC_LEAVE_LIST
  as select from ZI_LEAVE_REQUEST
{
  @UI.lineItem: [{ position: 10, label: 'Leave ID' }]
  @UI.selectionField: [{ position: 10 }]
  key LeaveID,
  @UI.lineItem: [{ position: 20 }]
      EmployeeID,
  @UI.lineItem: [{ position: 30 }]
      StartDate,
  @UI.lineItem: [{ position: 40 }]
      EndDate,
  @UI.lineItem: [{ position: 50,
                   criticality: 'StatusCriticality' }]
      Status,
      StatusCriticality  " calculated field for color
}

